+    try {
+        // biome-ignore lint/style/noProcessEnv: CLI utilities fall back to raw env variables when shared config is unavailable.
+        if (typeof process === 'undefined' || !process?.env) {
+            return null;
+        }
+        // biome-ignore lint/style/noProcessEnv: CLI utilities fall back to raw env variables when shared config is unavailable.
