+import { sweetLinkDebug } from '../env.js';
+/** Extracts a readable message from unknown error-like values. */
+export function extractEventMessage(event, prefix) {
+    const parts = [];
+    if (prefix) {
+        parts.push(prefix);
+    }
+    if (typeof event === 'string') {
+        parts.push(event);
+    }
+    else if (event instanceof Error) {
